  Cur_RepeatedLines RECORD;
  Cur_RepeatedLinesEco RECORD;
  v_Message varchar2(2000):='';
  V_HaveRepeatedLines BOOLEAN:=FALSE;
  V_ContinueBlock BOOLEAN:=FALSE;
  v_CampaignID  varchar2(32):='';
  v_OrderID varchar2(32):='';

BEGIN

  IF AD_isTriggerEnabled()='N' THEN IF DELETING THEN RETURN OLD; ELSE RETURN NEW; END IF;
  END IF;

  IF (INSERTING OR  UPDATING)THEN
    IF(:new.Docstatus='DR' and :new.issotrx='N') THEN

		v_OrderID := coalesce(:new.c_order_id,'ND');
		IF (v_OrderID<>'ND') THEN

			SELECT COALESCE((SELECT C_CAMPAIGN_ID
			FROM c_order 
			WHERE c_order_id=v_OrderID),'ND')
			INTO v_CampaignID
			FROM DUAL;

			IF (v_CampaignID<>'ND') THEN
				:new.c_campaign_id:=v_CampaignID;
			ELSE
				:new.c_campaign_id:=null;
			END IF;
		END IF;
    END IF;
  END IF;

  END SSIMACC_CAPMAIGN_TRG
